using Ledgerly.Domain.Entities; using Microsoft.EntityFrameworkCore; namespace Ledgerly.Infrastructure.Persistence; public sealed class LedgerlyDbContext:DbContext{ public LedgerlyDbContext(DbContextOptions<LedgerlyDbContext> options):base(options){} public DbSet<Account> Accounts=>Set<Account>(); public DbSet<JournalEntry> JournalEntries=>Set<JournalEntry>(); public DbSet<Contact> Contacts=>Set<Contact>(); public DbSet<Invoice> Invoices=>Set<Invoice>(); public DbSet<Bill> Bills=>Set<Bill>(); public DbSet<Expense> Expenses=>Set<Expense>(); public DbSet<TaxCode> TaxCodes=>Set<TaxCode>(); public DbSet<BankStatement> BankStatements=>Set<BankStatement>(); public DbSet<BankStatementLine> BankStatementLines=>Set<BankStatementLine>(); public DbSet<RecurringSchedule> RecurringSchedules=>Set<RecurringSchedule>(); public DbSet<RecurringScheduleRun> RecurringScheduleRuns=>Set<RecurringScheduleRun>(); protected override void OnModelCreating(ModelBuilder modelBuilder){modelBuilder.ApplyConfigurationsFromAssembly(typeof(LedgerlyDbContext).Assembly);} }
